const user = $input.all()[0]?.json;
const context = $('Contexto Mensaje').first().json;

const msg = (context.msg_body || "").trim().toLowerCase();
let intent = "menu";

if (msg === "recarga" || msg === "recargar") {
  intent = "recarga";
} else if (msg.includes("saldo")) {
  intent = "saldo";
} else if (/^\d+$/.test(msg) && msg.length >= 4) {
  intent = "reference";
} else {
  intent = "menu";
}

return [{
  json: {
    phone: context.phone,
    name: context.name,
    msg_body: context.msg_body,
    bot_phone: context.bot_phone,
    user_exists: !!user?.phone,
    balance: parseFloat(user?.balance) || 0,
    qr_token: user?.qr_code_token || null,
    intent: intent
  }
}];

