const item = $input.item.json;
const ref = item.msg_body.toUpperCase().trim();

return {
  ...item,
  ref_code: ref
};

const item = $input.item.json;
const responseBody = item.responseBody || item;
const errorObj = item.error;

const inputData = $('Limpiar Referencia').first().json;

let is_valid = false;
let amount = 0.00;
let error_msg = "";

let bodyObj = {};
if (typeof responseBody === 'string') {
  try {
    bodyObj = JSON.parse(responseBody);
  } catch (e) {
    bodyObj = {};
  }
} else {
  bodyObj = responseBody || {};
}

const errCode = bodyObj.error || "";
const rawMsg = bodyObj.message || errorObj?.message || "";

const payment = bodyObj.data?.user_bank_payment || bodyObj.user_bank_payment;

if (!errorObj && payment) {
  const status = payment.status;
  if (status === 'verified' || status === 'paid') {
    is_valid = true;
    amount = parseFloat(payment.amount) || 0.00;
  } else {
    error_msg = "El pago no está en estado verificado o pagado (estado actual: " + status + ").";
  }
} else {
  if (errCode === 'PAYMENT_NOT_FOUND' || rawMsg.includes('payment not found') || rawMsg.includes('PAYMENT_NOT_FOUND')) {
    error_msg = "No encontramos ningún Pago Móvil registrado con ese número de referencia en nuestro banco. Por favor verifica los datos e inténtalo de nuevo.";
  } else if (errCode === 'PAYMENT_AMOUNT_NOT_VALID' || rawMsg.includes('payment amount not valid')) {
    error_msg = "El monto del pago verificado no es válido.";
  } else if (rawMsg) {
    error_msg = rawMsg;
  } else {
    error_msg = "La referencia no se pudo verificar en este momento. Inténtalo de nuevo más tarde.";
  }
}

return {
  phone: inputData.phone,
  name: inputData.name,
  msg_body: inputData.msg_body,
  bot_phone: inputData.bot_phone,
  user_exists: inputData.user_exists,
  balance: inputData.balance,
  qr_token: inputData.qr_token,
  ref_code: inputData.ref_code,
  is_valid_ref: is_valid,
  payment_amount: amount,
  error_msg: error_msg
};

